/**
 * The single help file for the whole project. Holds, in one module:
 *  - HelpEntry (the shared type), HELP: structured entries for common built-ins
 *  - EXTRA_HELP / EXTRA_SYNTAX: one-line summaries + short syntax for the rest
 *  - BASE_REF / DOUBLE_REF + docUrl: MathWorks documentation links
 *  - builtinHelp: renders the MATLAB-style help block for a name
 *  - every per-toolbox HELP_<TOOLBOX> map (consumed by the owning tb/<toolbox>.ts module)
 *
 * Dependency note: tb/* import the HELP_<TOOLBOX> maps from here, so this file must NOT import
 * ../tb at load time (that would be a cycle, and a runtime require would break the browser ESM
 * bundle). The renderer needs the toolbox registry only at call time, so tb/index.ts injects it
 * via setToolboxHelpRefs() — this file keeps no load-time dependency on ../tb.
 */
import type { ToolboxModule } from '../tb/types';

/** Help entry for a built-in: a one-line summary plus optional syntax/description/see-also/examples. */
export interface HelpEntry {
  summary: string;
  syntax: string[];
  seealso?: string[];
  description?: string[];
  examples?: string[];
}

// Toolbox registry refs, injected by tb/index.ts once it has built them (setToolboxHelpRefs). They
// stay empty until then, so help resolves base built-ins even if the toolbox layer never loads.
let FUNC_TOOLBOX: Map<string, ToolboxModule> = new Map();
let TOOLBOX_HELP: Record<string, HelpEntry | string> = {};
/** Wire the toolbox registry into the help renderer (called by tb/index.ts at module load). */
export function setToolboxHelpRefs(funcToolbox: Map<string, ToolboxModule>, toolboxHelp: Record<string, HelpEntry | string>): void {
  FUNC_TOOLBOX = funcToolbox;
  TOOLBOX_HELP = toolboxHelp;
}

