  RandStream: { summary: 'RandStream creates a random number stream using a specified pseudorandom number generator algorithm.', syntax: [], description: ['RandStream creates a random number stream using a specified pseudorandom number generator algorithm. You can generate pseudorandom numbers in MATLAB ® from one or more random number streams.'], seealso: ['rng', 'rand', 'randi', 'randn', 'randperm'] },
  GraphPlot: { summary: 'Graph plots are the primary way to visualize graphs and networks created using the graph and digraph functions.', syntax: [], description: ['Graph plots are the primary way to visualize graphs and networks created using the graph and digraph functions. After you create a GraphPlot object, you can modify aspects of the plot by changing its property values.'], seealso: ['graph', 'digraph', 'plot'] },
