  colmmd: { summary: 'Column minimum degree permutation (deprecated; use colamd)', syntax: ['p = colmmd(S)'], description: ['p = colmmd(S) returns a permutation vector p such that S(:,p) has a sparser LU factorization. colmmd is superseded by colamd, which is faster and more reliable.'], seealso: ['colamd', 'symmmd', 'symamd', 'symrcm'] },
