  luinc: { summary: 'Incomplete LU factorization (deprecated; use ilu)', syntax: ['[L,U] = luinc(A,droptol)', '[L,U,P] = luinc(A,"0")'], description: ['luinc(A,droptol) computes an incomplete LU factorization of sparse A, dropping fill-in elements whose magnitude is less than droptol. Used as a preconditioner for iterative solvers. Superseded by ilu.'], seealso: ['ilu', 'ichol', 'gmres', 'pcg'] },
