  'vander': { summary: 'Vandermonde matrix', syntax: ['A = vander(v)'], description: ['A = vander(v) returns the [Vandermonde Matrix](vander.html#bubf_mp-2) such that its columns are powers of the vector v.'] },
  'toeplitz': { summary: 'Toeplitz matrix', syntax: ['T = toeplitz(c,r)', 'T = toeplitz(r)'], description: ['T = toeplitz(c,r) returns a nonsymmetric [Toeplitz matrix](toeplitz.html#buw23nm-3) with c as its first column and r as its first row. If the first elements of c and r differ, toeplitz issues a warning and uses the column element for the diagonal.'] },
  'sqrtm': { summary: 'Matrix square root', syntax: ['X = sqrtm(A)'], description: ['X = sqrtm(A) returns the principal square root of the matrix A, that is, X*X = A.'] },
  'subspace': { summary: 'Angle between two subspaces', syntax: ['theta = subspace(A,B)'], description: ['theta = subspace(A,B) finds the angle between two subspaces specified by the columns of A and B. If A and B are column vectors of unit length, this is the same as acos(abs(A\'*B)).'] },
  'svds': { summary: 'A few singular values', syntax: ['s = svds(A)', 's = svds(A,k)'], description: ['s = svds(A) returns a vector of the six largest singular values of matrix A. This is useful when computing all of the singular values with svd is computationally expensive, such as with large sparse matrices.'] },
  'xcorr': { summary: 'Cross-correlation', syntax: ['r = xcorr(x,y)', 'r = xcorr(x)'], description: ['r = xcorr(x,y) returns the [cross- correlation](xcorr.html#mw_01b546db-b642-4f02-8625-16078810d80f) of two discrete-time sequences. Cross-correlation measures the similarity between a vector x and shifted (lagged) copies of a vector y as a function of the lag. If x and y have different lengths, the function appends zeros to the end of the shorter vector so it has the same length as the other.'] },
  'xcov': { summary: 'Cross-covariance', syntax: ['c = xcov(x,y)', 'c = xcov(x)'], description: ['c = xcov(x,y) returns the [cross- covariance](xcov.html#mw_4c5c453a-a1ed-4444-a551-d34a086f274d) of two discrete-time sequences. Cross-covariance measures the similarity between a vector x and shifted (lagged) copies of a vector y as a function of the lag. If x and y have different lengths, the function appends zeros to the end of the shorter vector so it has the same length as the other.'] },
  'smoothdata': { summary: 'Smooth noisy data', syntax: ['B = smoothdata(A)', 'B = smoothdata(A,dim)'], description: ['B = smoothdata(A) smooths entries of A using a moving average. smoothdata determines the moving window size from the entries in A. The window slides down the length of the vector, computing an average over the elements within each window.'] },
  'smoothdata2': { summary: 'Smooth noisy 2-D data', syntax: ['S = smoothdata2(A)', 'S = smoothdata2(A,method)'], description: ['S = smoothdata2(A) smooths entries of A using a moving average. smoothdata2 determines the moving window size from the entries in A.'] },
  'union': { summary: 'Set union', syntax: ['polyout = union(poly1,poly2)', 'polyout = union(polyvec)'] },
  'setdiff': { summary: 'Set difference', syntax: ['C = setdiff(A,B)', 'C = setdiff(A,B,setOrder)'], description: ['C = setdiff(A,B) returns the data in A that is not in B, with no repetitions. C is in sorted order.'] },
  'setxor': { summary: 'Set symmetric difference', syntax: ['C = setxor(A,B)', 'C = setxor(A,B,setOrder)'], description: ['C = setxor(A,B) returns the data of A and B that are not in their intersection (the symmetric difference), with no repetitions. That is, setxor returns the data that occurs in A or B, but not both. C is in sorted order.'] },
