  'strcmp': { summary: 'Compare strings for equality', syntax: ['tf = strcmp(s1,s2)'], description: ['tf = strcmp(s1,s2) compares s1 and s2 and returns 1 (true) if the two are identical and 0 (false) otherwise. Text is considered identical if the size and content of each are the same. The return result tf is of data type logical.'] },
  'strcmpi': { summary: 'Compare strings ignoring case', syntax: ['tf = strcmpi(s1,s2)'], description: ['tf = strcmpi(s1,s2) compares s1 and s2, ignoring any differences in letter case, and returns 1 (true) if the two are identical and 0 (false) otherwise. Text is considered identical if the size and content of each are the same, aside from case. The return result tf is of data type logical.'] },
  'strncmp': { summary: 'Compare the first n characters', syntax: ['tf = strncmp(s1,s2,n)'], description: ['tf = strncmp(s1,s2,n) compares up to n characters of s1 and s2. The function returns 1 (true) if the two are identical and 0 (false) otherwise. Text is considered identical if the content of each is the same up to the end or the first n characters, whichever comes first. The return result tf is of data type logical.'] },
  'strncmpi': { summary: 'Compare first n characters, ignore case', syntax: ['tf = strncmpi(s1,s2,n)'], description: ['tf = strncmpi(s1,s2,n) compares up to n characters of s1 and s2, ignoring any differences in letter case, and returns true(1) if the two are identical and false(0) otherwise. Text is considered identical if the content of each is the same up to the end or the first n characters, whichever comes first, ignoring case. The return result tf is of data type logical.'] },
  'strrep': { summary: 'Replace a substring', syntax: ['newStr = strrep(str,old,new)'], description: ['**Note**'] },
  'strcat': { summary: 'Concatenate strings', syntax: ['s = strcat(s1,...,sN)'], description: ['**Note**'] },
  'strfind': { summary: 'Find a substring', syntax: ['k = strfind(str,pat)'] },
  'strtok': { summary: 'Extract the first token', syntax: ['token = strtok(str)', 'token = strtok(str,delimiters)'], description: ['token = strtok(str) parses str from left to right, using whitespace characters as delimiters, and returns part or all of the text in token. First, strtok ignores any leading whitespace in str. Then, strtok starts at the first character that is not whitespace, and includes all characters up to, but not including, the next whitespace character. strtok returns that part of the text in token. If strtok does not find any whitespace to use as a delimiter, then token includes all characters up to, and including, the end of str.'] },
  'sscanf': { summary: 'Read formatted data from a string', syntax: ['A = sscanf(str,formatSpec)', 'A = sscanf(str,formatSpec,sizeA)'] },
