export function builtinHelp(name: string): string | null {
  // Class-qualified symbolic help: `help sym/asin` / `help sym.asin` → the symbolic
  // overload's page, even when the bare name defaults to the numeric (double) page.
  const symQual = name.match(/^sym[./](\w+)$/);
  if (symQual) {
    const base = symQual[1];
    const se = HELP[base] ?? (typeof TOOLBOX_HELP[base] === 'object' ? TOOLBOX_HELP[base] as HelpEntry : undefined);
    const summary = se?.summary ?? EXTRA_HELP[base] ?? (typeof TOOLBOX_HELP[base] === 'string' ? TOOLBOX_HELP[base] as string : `Symbolic overload of ${base}`);
    let s = ` sym/${base} - ${summary}\n\n    Symbolic Math Toolbox (symbolic overload of ${base})`;
    const syn = compactHelpLines(se?.syntax, MAX_HELP_SYNTAX_LINES);
    if (syn.length) s += `\n\n    Syntax\n` + indentHelp(syn);
    s += `\n\n    Documentation for sym/${base}\n      ${docUrl(name)}`;
    return s;
  }
  // Overloaded (numeric + symbolic) functions cross-link to their symbolic page.
  const overloaded = SYM_OVERLOAD.has(name.toLowerCase());
  const withSym = (sa: string[] | undefined) => {
    const list = sa ? [...sa] : [];
    if (overloaded && !list.includes(`sym.${name}`)) list.push(`sym.${name}`);
    return list;
  };
  const baseE = HELP[name] ?? KEYWORD_HELP[name];
  const tbE = typeof TOOLBOX_HELP[name] === 'object' ? TOOLBOX_HELP[name] as HelpEntry : undefined;
  // A summary-only base entry must not shadow a richer toolbox entry (e.g. lyap → Control System Toolbox).
  const entry = baseE && (baseE.description?.length || baseE.syntax?.length) ? baseE : (tbE ?? baseE);
  if (entry) {
    const tb = entry === tbE ? FUNC_TOOLBOX.get(name) : undefined;
    const tag = tb ? `\n\n    Toolbox: ${tb.name}` : '';
    const e = entry;
    let s = ` ${name} - ${e.summary}`;
    const syn = compactHelpLines(e.syntax, MAX_HELP_SYNTAX_LINES);
    const desc = compactHelpLines(e.description, MAX_HELP_DESCRIPTION_LINES);
    const ex = compactHelpLines(e.examples, MAX_HELP_EXAMPLE_LINES);
    if (syn.length) s += `\n\n    Syntax\n` + indentHelp(syn);   // skip the header when empty
    if (desc.length) s += `\n\n    Description\n` + indentHelp(desc);
    if (ex.length) s += `\n\n    Examples\n` + indentHelp(ex);
    const sa = withSym(e.seealso);
    if (sa.length) s += `\n\n    See also ${sa.join(', ')}`;
    s += tag + `\n\n    Documentation for ${name}\n      ${docUrl(name)}`;
    return s;
  }
  const one = EXTRA_HELP[name] ?? (typeof TOOLBOX_HELP[name] === 'string' ? TOOLBOX_HELP[name] as string : undefined);
  if (one) {
    const tb = FUNC_TOOLBOX.get(name);
    const tag = tb ? `\n\n    Toolbox: ${tb.name}` : '';
    let s = ` ${name} - ${one}`;
    const syn = EXTRA_SYNTAX[name];
    const compactSyn = compactHelpLines(syn, MAX_HELP_SYNTAX_LINES);
    if (compactSyn.length) s += `\n\n    Syntax\n` + indentHelp(compactSyn);
    const sa = withSym(undefined);
    if (sa.length) s += `\n\n    See also ${sa.join(', ')}`;
    s += tag + `\n\n    Documentation for ${name}\n      ${docUrl(name)}`;
    return s;
  }
  return null;
}

