    ff2n: { summary: 'Returns a 2n-by-n numeric matrix dFF2 containing the treatments of a full factorial design for n two-level factors.', syntax: ['dFF2 = ff2n(n)'], seealso: ['fullfact', 'fracfact', 'fracfactgen', 'hadamard'] },
